class Main {
  public static void main(String[] args) {
    for (int i = 1; i <= 5; i++) {
      if (i == 3) {
        System.out.println("Breaking early!");
        break; // Destroys the loop completely
      }
      System.out.println(i);
    }
    System.out.println("Outside.");
  }
}

class Main {
  public static void main(String[] args) {
    // Print numbers 1 to 5, but skip 3
    for (int i = 1; i <= 5; i++) {
      if (i == 3) {
        continue; // Skips printing 3, jumps straight to i=4
      }
      System.out.println(i);
    }
  }
}
